function slugify(value) {
  return String(value || "task")
    .normalize("NFKD")
    .replace(/[^\w\s-]/g, "")
    .trim()
    .replace(/\s+/g, "-")
    .replace(/_+/g, "-")
    .toLowerCase()
    .slice(0, 48) || "task";
}

const input = $json;
function pick(...keys) {
  for (const key of keys) {
    if (input[key] != null && input[key] !== "") return input[key];
  }
  return "";
}

const taskTitle = pick("task_title", "Task Title");
if (!taskTitle) {
  throw new Error("Task Title は必須です");
}
const targetRepository = pick("target_repository", "Target Repository") || "okamyuji/prd-design-implementation-agent";
const [owner, repo] = targetRepository.split("/");
if (!owner || !repo) {
  throw new Error("target_repository は owner/repo 形式で指定してください");
}

const baseBranch = pick("base_branch", "Base Branch") || "main";
const constraints = pick("additional_constraints", "Additional Constraints");
const instruction = pick("implementation_instruction", "Implementation Instruction");
if (!instruction) {
  throw new Error("Implementation Instruction は必須です");
}

const now = new Date();
const stamp = now.toISOString().replace(/[-:]/g, "").replace(/\..+/, "Z");
const slug = slugify(taskTitle);
const branchName = "agent/" + stamp + "-" + slug;
const docsPath = "docs/design-docs/" + stamp + "-" + slug + ".md";

const PRD_TEMPLATE_URL = "https://github.com/okamyuji/prd-design-implementation-agent/blob/main/templates/prd-template-ja.md";
const DESIGN_DOC_TEMPLATE_URL = "https://github.com/okamyuji/prd-design-implementation-agent/blob/main/templates/design-doc-template-ja.md";

const userInput = {
  task_title: taskTitle,
  target_repository: targetRepository,
  base_branch: baseBranch,
  implementation_instruction: instruction,
  additional_constraints: constraints || null,
  prd_template_url: PRD_TEMPLATE_URL,
  design_doc_template_url: DESIGN_DOC_TEMPLATE_URL,
};

const systemRules = [
  "あなたはプロダクトマネージャー、ソフトウェアアーキテクト、QAリードを兼ねる日本語の実装仕様作成者です。",
  "下記 user_input(JSON) からPRDとDesignDocを作成してください。",
  "",
  "必須条件:",
  "- 日本語で書く",
  "- 詳細かつMECEに整理する",
  "- DesignDocにはロジックツリーを入れる",
  "- 実装者が機械的に実装できる粒度まで分解する",
  "- TDDで進める計画を書く",
  "- カバレッジ80%以上を品質ゲートに入れる",
  "- 正常系、異常系、境界値、エッジケース、E2Eを具体化する",
  "- Formatter、Linter、静的解析、テスト、ビルドをすべてPassさせる条件を書く",
  "- 「テストを通すためだけ」のテストではなく、本質的なテスト観点を書く",
  "- PR本文には実装条件と完了基準を、レビュー担当の人間が読みやすい形で記載する",
  "",
  "テンプレートは user_input.prd_template_url および user_input.design_doc_template_url のGitHub上Markdownを参照すること。",
  "",
  "出力スキーマ(必ず全フィールド埋める。Markdownフェンスやコメントは禁止):",
  "{",
  '  "prd_markdown": "PRD本文Markdown",',
  '  "design_doc_markdown": "DesignDoc本文Markdown",',
  '  "pr_title": "GitHub PRタイトル(80文字以内)",',
  '  "pr_body": "GitHub PR本文Markdown"',
  "}",
].join("\n");

const prompt = systemRules + "\n\nuser_input:\n" + JSON.stringify(userInput, null, 2);

return [{
  json: {
    owner,
    repo,
    target_repository: targetRepository,
    base_branch: baseBranch,
    branch_name: branchName,
    docs_path: docsPath,
    task_title: taskTitle,
    implementation_instruction: instruction,
    additional_constraints: constraints,
    requested_at: now.toISOString(),
    prompt,
  },
}];

function firstString(value) {
  if (typeof value === "string") return value;
  if (Array.isArray(value)) return value.map(firstString).find(Boolean) || "";
  if (value && typeof value === "object") {
    for (const key of ["text", "content", "parts", "output", "response", "result", "message", "data"]) {
      if (value[key] === undefined) continue;
      const found = firstString(value[key]);
      if (found) return found;
    }
  }
  return "";
}

function parseJson(raw) {
  if (raw && typeof raw === "object" && raw.prd_markdown) return raw;
  const text = firstString(raw) || JSON.stringify(raw);
  const cleaned = text
    .replace(new RegExp("^\\x60{3}(?:json)?\\s*", "i"), "")
    .replace(new RegExp("\\s*\\x60{3}$", "i"), "")
    .trim();
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const start = cleaned.indexOf("{");
    const end = cleaned.lastIndexOf("}");
    if (start >= 0 && end > start) {
      try { return JSON.parse(cleaned.slice(start, end + 1)); } catch (_) {}
    }
    throw new Error(
      "Geminiの出力をJSONとして解釈できませんでした。出力が途中で打ち切られている可能性があります(maxOutputTokens不足)。先頭200文字: "
      + cleaned.slice(0, 200)
    );
  }
}

const base = $("Prepare Request").first().json;
const generated = parseJson($json);

const required = ["prd_markdown", "design_doc_markdown", "pr_title", "pr_body"];
for (const key of required) {
  if (!generated[key]) throw new Error("Gemini output missing " + key);
}

// セキュリティガード: 長さ制限(プロンプト注入とトークン消費の上限を機械的に確保)
const MAX_LEN = {
  prd_markdown: 20000,
  design_doc_markdown: 30000,
  pr_title: 200,
  pr_body: 5000
};
for (const key of required) {
  const max = MAX_LEN[key];
  if (typeof generated[key] === "string" && generated[key].length > max) {
    throw new Error("Gemini output " + key + " exceeds " + max + " chars (got " + generated[key].length + ")");
  }
}

// セキュリティガード: 漏えいパターン・XSSベクトル・秘匿情報パターンの検出
const FORBIDDEN_PATTERNS = [
  { name: "script tag", re: /<script[\s>]/i },
  { name: "javascript: scheme", re: /javascript:/i },
  { name: "data:text/html", re: /data:text\/html/i },
  { name: "github PAT", re: /\bghp_[A-Za-z0-9]{20,}/ },
  { name: "github fine-grained PAT", re: /\bgithub_pat_[A-Za-z0-9_]{20,}/ },
  { name: "PEM private key", re: /-----BEGIN [A-Z ]*PRIVATE KEY-----/ },
  { name: "AWS access key", re: /\b(AKIA|ASIA)[0-9A-Z]{16}\b/ }
];
for (const key of required) {
  if (typeof generated[key] !== "string") continue;
  for (const { name, re } of FORBIDDEN_PATTERNS) {
    if (re.test(generated[key])) {
      throw new Error("Gemini output " + key + " contains forbidden pattern: " + name);
    }
  }
}

// 制御文字の除去(改行とタブは保持)
for (const key of required) {
  if (typeof generated[key] === "string") {
    generated[key] = generated[key].replace(/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/g, "");
  }
}

const prdDocTitle = "PRD - " + base.task_title + " - " + base.requested_at.slice(0, 10);
const designDocTitle = "DesignDoc - " + base.task_title + " - " + base.requested_at.slice(0, 10);
const designDocWithLinks = [
  generated.design_doc_markdown,
  "",
  "---",
  "",
  "## Automation Metadata",
  "",
  "- Requested at: " + base.requested_at,
  "- Target repository: " + base.target_repository,
  "- Base branch: " + base.base_branch,
  "- Working branch: " + base.branch_name,
  "",
].join("\n");

return [{
  json: {
    ...base,
    ...generated,
    prd_doc_title: prdDocTitle,
    design_doc_title: designDocTitle,
    design_doc_markdown: designDocWithLinks,
    design_doc_base64: Buffer.from(designDocWithLinks, "utf8").toString("base64"),
    commit_message: "Add DesignDoc for " + base.task_title,
  },
}];

const base = $("Build PRD Upload Body").first().json;
const upload = $json;
const id = upload.id || upload.fileId;
return [{
  json: {
    ...base,
    prd_doc_id: id,
    prd_doc_url: "https://docs.google.com/document/d/" + id + "/edit",
  },
}];

const base = $("Attach PRD Doc URL").first().json;
const upload = $json;
const id = upload.id || upload.fileId;
const designDocUrl = "https://docs.google.com/document/d/" + id + "/edit";
// design_doc_markdown と pr_body には Google Doc URL を残さない
// (公開リポジトリの履歴に Doc ID が残るのを避けるため)
const designDocMarkdown = base.design_doc_markdown;
return [{
  json: {
    ...base,
    design_doc_id: id,
    design_doc_url: designDocUrl,
    design_doc_markdown: designDocMarkdown,
    design_doc_base64: Buffer.from(designDocMarkdown, "utf8").toString("base64"),
    pr_body: [
      base.pr_body,
      "",
      "---",
      "",
      "## Generated Docs",
      "",
      "- DesignDoc markdown path in this PR: " + base.docs_path,
      "",
    ].join("\n"),
  },
}];

const base = $("Attach DesignDoc URL").first().json;
const sha = $json.object?.sha;
if (!sha) throw new Error("Could not read base branch SHA from GitHub response");
return [{ json: { ...base, base_sha: sha } }];

const prep = $("Prepare GitHub Payload").first().json;
const pr = $("Create GitHub PR").first().json;
const bedrock = $("Parse Bedrock Result").first().json;
return [{
  json: {
    status: "implementation_committed_by_bedrock",
    task_title: prep.task_title,
    target_repository: prep.target_repository,
    branch_name: prep.branch_name,
    design_doc_path: prep.docs_path,
    prd_doc_url: prep.prd_doc_url,
    design_doc_url: prep.design_doc_url,
    pull_request_url: pr.html_url,
    pull_request_number: pr.number,
    bedrock_model: bedrock.model_id,
    files_changed: bedrock.files_changed,
    next_step: "PR is ready for review. CodeRabbit / Gemini Code Assist will auto-review. A human reviewer makes the final approval."
  }
}];

