let payload = $json;
if (payload && typeof payload === "object" && payload.result && typeof payload.result === "object") {
  payload = payload.result;
}
if (typeof payload === "string") {
  try { payload = JSON.parse(payload); } catch (_) {}
}
if (!payload || typeof payload !== "object") {
  throw new Error("Lambda payload is not an object: " + JSON.stringify($json).slice(0, 300));
}
if (payload.errorMessage) {
  throw new Error("Lambda error: " + payload.errorMessage);
}
if (!payload.summary_markdown || !Array.isArray(payload.files_changed)) {
  throw new Error("Lambda payload missing fields: " + JSON.stringify(payload).slice(0, 500));
}
return [{ json: payload }];

const base = $json;
const boundary = "n8n-html-" + Date.now() + "-" + Math.random().toString(36).slice(2);
const metadata = JSON.stringify({
  name: base.prd_doc_title,
  mimeType: "application/vnd.google-apps.document",
  parents: ["REPLACE_WITH_YOUR_DRIVE_FOLDER_ID"]
});
const html = "<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body>" + (base.prd_html || "") + "</body></html>";
const body = [
  "--" + boundary,
  "Content-Type: application/json; charset=UTF-8",
  "",
  metadata,
  "--" + boundary,
  "Content-Type: text/html; charset=UTF-8",
  "",
  html,
  "--" + boundary + "--",
  ""
].join("\r\n");
return [{ json: { ...base, prd_multipart_body: body, prd_multipart_boundary: boundary } }];

const base = $json;
const boundary = "n8n-html-" + Date.now() + "-" + Math.random().toString(36).slice(2);
const metadata = JSON.stringify({
  name: base.design_doc_title,
  mimeType: "application/vnd.google-apps.document",
  parents: ["REPLACE_WITH_YOUR_DRIVE_FOLDER_ID"]
});
const html = "<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body>" + (base.design_doc_html || "") + "</body></html>";
const body = [
  "--" + boundary,
  "Content-Type: application/json; charset=UTF-8",
  "",
  metadata,
  "--" + boundary,
  "Content-Type: text/html; charset=UTF-8",
  "",
  html,
  "--" + boundary + "--",
  ""
].join("\r\n");
return [{ json: { ...base, designdoc_multipart_body: body, designdoc_multipart_boundary: boundary } }];

const expected = $env.PRD_AGENT_FORM_SECRET || "";
if (!expected) {
  throw new Error("Server misconfiguration: PRD_AGENT_FORM_SECRET is not set on the n8n container.");
}

const items = $input.all();
for (const item of items) {
  const provided = item.json["Shared Secret"] || item.json.shared_secret || "";
  if (provided.length !== expected.length) {
    throw new Error("Unauthorized: invalid shared secret");
  }
  let diff = 0;
  for (let i = 0; i < expected.length; i++) {
    diff |= provided.charCodeAt(i) ^ expected.charCodeAt(i);
  }
  if (diff !== 0) {
    throw new Error("Unauthorized: invalid shared secret");
  }
  delete item.json["Shared Secret"];
  delete item.json.shared_secret;
}
return items;
